import{c as t,Q as r,j as a,m as o}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Smart Set Builder","description":"","frontmatter":{},"headers":[],"relativePath":"ru/user-guide/smart-set-builder.md","filePath":"ru/user-guide/smart-set-builder.md","lastUpdated":null}'),i={name:"ru/user-guide/smart-set-builder.md"};function d(s,e,l,c,n,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="smart-set-builder" tabindex="-1">Smart Set Builder <a class="header-anchor" href="#smart-set-builder" aria-label="Permalink to &quot;Smart Set Builder&quot;">​</a></h1><p>Аудитория: DJs и продвинутые пользователи UI<br> Цель: генерировать ordered read-only set previews<br> Тип: how-to</p><p>Smart Set Builder в tab <code>SET</code> строит ordered preview из manual seeds или auto anchors. Он не изменяет библиотеку. Preview добавляется в current set только явным действием.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>SET требует feature-complete candidates:</p><ul><li>SONARA features;</li><li>MERT embeddings;</li><li>MAEST embeddings;</li><li>CLAP audio embeddings.</li></ul><p>MAEST genre labels не являются selection source для SET. MAEST embeddings могут использоваться как один similarity signal.</p><h2 id="seed-source" tabindex="-1">Seed source <a class="header-anchor" href="#seed-source" aria-label="Permalink to &quot;Seed source&quot;">​</a></h2><ul><li><code>Manual</code>: использовать selected tracks как seeds.</li><li><code>Auto</code>: выбрать первый anchor из feature-complete library, затем построить related waypoint anchors и bridge tracks.</li></ul><p>Manual seeds с одинаковым known artist отклоняются. Generated previews тоже сохраняют строгий known-artist guard.</p><h2 id="core-controls" tabindex="-1">Core controls <a class="header-anchor" href="#core-controls" aria-label="Permalink to &quot;Core controls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Meaning</th></tr></thead><tbody><tr><td><code>Set mode</code></td><td>Similar crate, weird adjacent, balanced set или discovery.</td></tr><tr><td><code>Track limit</code></td><td>Количество preview tracks, от 1 до 500.</td></tr><tr><td><code>Auto anchors</code></td><td>Количество automatic anchors, от 1 до 5.</td></tr><tr><td><code>Energy curve</code></td><td>Warmup, balanced, peak или wave intensity shape.</td></tr><tr><td><code>Diversity</code></td><td>Насколько широко route исследует related candidates.</td></tr></tbody></table><h2 id="bpm-controls" tabindex="-1">BPM controls <a class="header-anchor" href="#bpm-controls" aria-label="Permalink to &quot;BPM controls&quot;">​</a></h2><p><code>BPM mode = general</code> сохраняет обычную transition compatibility. <code>low_to_high</code> или <code>high_to_low</code> добавляют actual BPM trajectory.</p><p>Если в file tags есть BPM, SET предпочитает его. SONARA BPM используется как fallback. Half/double tempo matching помогает transition compatibility, но не переписывает actual BPM trajectory.</p><h2 id="classifier-controls" tabindex="-1">Classifier controls <a class="header-anchor" href="#classifier-controls" aria-label="Permalink to &quot;Classifier controls&quot;">​</a></h2><p>Promoted classifier scores - optional modifiers. Missing scores остаются neutral. Preference может быть positive или negative, flow - flat, rise или fall.</p><p><code>Reset sliders</code> сбрасывает diversity и classifier preference/flow values, но не меняет seed source, mode, limit, anchors, energy curve или BPM controls.</p><h2 id="добавить-preview" tabindex="-1">Добавить preview <a class="header-anchor" href="#добавить-preview" aria-label="Permalink to &quot;Добавить preview&quot;">​</a></h2><p>Сгенерируйте preview, послушайте, проверьте список и только потом используйте add action для переноса preview в current set. Export остается отдельным шагом.</p>',20)])])}const m=t(i,[["render",d]]);export{h as __pageData,m as default};
